// Diakritika-Helfer laut CLAUDE.md §6.6 — Tap-Buttons für Diakritika
// die auf US/DE-Tastaturen schwer zu tippen sind.
//
// Modi:
//   - 'hu' (default): á é í ó ö ő ú ü ű
//   - 'de':           ä ö ü ß
//
// Klick fügt das Zeichen am aktuellen Cursor ein und gibt Focus zurück
// auf das Eingabefeld.

import { type RefObject } from 'react'

const HU_CHARS = ['á', 'é', 'í', 'ó', 'ö', 'ő', 'ú', 'ü', 'ű']
const DE_CHARS = ['ä', 'ö', 'ü', 'ß']

type Lang = 'hu' | 'de'

type Props = {
  lang: Lang
  inputRef: RefObject<HTMLInputElement | null>
  onChange: (next: string) => void
}

export function DiacriticKeyboard({ lang, inputRef, onChange }: Props) {
  const chars = lang === 'hu' ? HU_CHARS : DE_CHARS

  function insert(ch: string) {
    const el = inputRef.current
    if (!el) return
    const start = el.selectionStart ?? el.value.length
    const end = el.selectionEnd ?? el.value.length
    const next = el.value.slice(0, start) + ch + el.value.slice(end)
    onChange(next)
    // Cursor hinter eingefügtes Zeichen positionieren
    requestAnimationFrame(() => {
      el.focus()
      el.setSelectionRange(start + ch.length, start + ch.length)
    })
  }

  return (
    <div
      style={{
        display: 'flex',
        flexWrap: 'wrap',
        gap: 6,
        justifyContent: 'center'
      }}
    >
      {chars.map((ch) => (
        <button
          key={ch}
          type="button"
          onMouseDown={(e) => e.preventDefault()}  // verhindert Focus-Verlust
          onClick={() => insert(ch)}
          style={{
            background: 'var(--white)',
            border: '1.5px solid var(--green)',
            color: 'var(--green)',
            width: 40,
            height: 40,
            borderRadius: 8,
            fontFamily: 'Georgia, serif',
            fontSize: '1.1rem',
            fontWeight: 700,
            cursor: 'pointer',
            padding: 0
          }}
        >
          {ch}
        </button>
      ))}
    </div>
  )
}
